SELECT platform_name
FROM vehicle_platforms
WHERE manufacturer = 'Ford' AND body_styles LIKE '%Crew Cab%';

SELECT * 
FROM customer_support
WHERE user_id = 1;

SELECT DISTINCT vp.platform_name
FROM vehicle_platforms AS vp
WHERE LOWER(vp.engine_types) LIKE "%1.6l%";

SELECT part_number
FROM vent_assemblies
WHERE platform_id = 0;

SELECT DISTINCT vp.manufacturer
FROM orders o
JOIN vehicle_platforms vp ON o.platform_id = vp.platform_id;

SELECT platform_id, COUNT(DISTINCT detail_id) AS num_compatibility_details
FROM compatibility_details
GROUP BY platform_id;

SELECT * 
FROM vent_assemblies
ORDER BY model_year_start DESC;

SELECT part_number 
FROM car_x_settings 
WHERE platform_id = 0 AND settings_type = 'FORD';

SELECT COUNT(*)
FROM vent_assemblies
WHERE model_year_start >= 2010 AND model_year_end <= 2015;

SELECT o.order_id, o.user_id, o.platform_id, o.product_type, o.order_date, o.status, o.product_id, o.quantity, o.total_price, o.shipping_address, o.tracking_number
FROM orders o
INNER JOIN customer_support c ON o.order_id = c.order_id;

SELECT platform_id, platform_name
FROM vehicle_platforms
ORDER BY platform_id ASC;

SELECT COUNT(DISTINCT platform_id)
FROM vehicle_platforms
WHERE engine_types LIKE '%3.5L V6%';
